def parse_yyyy_mm_dd(raw: str) -> date:
    return datetime.strptime(raw, "%Y-%m-%d").date()


def parse_interval_date(raw: Optional[str]) -> date:
    if raw is None:
        return datetime.now(timezone.utc).date()

    txt = str(raw).strip()
    if not txt:
        return datetime.now(timezone.utc).date()

    return datetime.fromisoformat(txt.replace("Z", "+00:00")).date()

def _parse_days_to_process_json(days_json: Optional[str]) -> Optional[List[date]]:
    if not days_json:
        return None
    if isinstance(days_json, str) and days_json.strip() == "":
        return None

    try:
        raw = json.loads(days_json)
    except Exception as exc:
        raise ValueError(f"days_to_process_json is not valid JSON: {exc}")

    if not isinstance(raw, list):
        raise ValueError("days_to_process_json must be a JSON array of 'YYYY-MM-DD' strings")

    out: List[date] = []
    for val in raw:
        if not isinstance(val, str):
            raise ValueError("days_to_process_json items must be strings 'YYYY-MM-DD'")
        day_str = val.strip()
        try:
            day_val = datetime.strptime(day_str, "%Y-%m-%d").date()
        except Exception:
            raise ValueError(f"Invalid day '{day_str}'. Expected format YYYY-MM-DD")
        out.append(day_val)

    return sorted(set(out))


