def rename_columns_snake_case(df: pd.DataFrame) -> pd.DataFrame:
    def to_snake_case(name: str) -> str:
        out = str(name).replace(".", "_")
        out = "".join(ch if ch.isalnum() or ch == "_" else "_" for ch in out)
        while "__" in out:
            out = out.replace("__", "_")
        return out.strip("_").lower()

    out = df.copy()
    out.columns = [to_snake_case(c) for c in out.columns]
    return out

