# DELTA PARQUET READ FUNCTIONS
# ─────────────────────────────────────────────
def _safe_partition_read(
    dt: DeltaTable,
    partitions: List[Tuple[str, str, str]],
    columns: Optional[List[str]] = None,
) -> pd.DataFrame:
    try:
        return dt.to_pandas(partitions=partitions, columns=columns)
    except TypeError:
        return dt.to_pandas(partition_filters=partitions, columns=columns)


def read_delta_table(
    table_path: str,
    start_dt: Optional[date] = None,
    end_dt: Optional[date] = None,
    date_column: Optional[str] = None,
    partition_columns: Optional[List[str]] = None,
) -> pd.DataFrame:
    """
    Dynamic Delta reader.

    Behavior:
    - No filters → full table
    - Partition columns provided → partition pruning
    - Date column provided → pushdown filter
    - Fallback → pandas filter
    """

    dt = DeltaTable(table_path, storage_options=get_storage_options())
    cols = list(dt.schema().to_pyarrow().names)
    colset = set(cols)

    # --- 1. No filters → full table ---
    if not start_dt or not end_dt:
        return dt.to_pandas()

    # --- 2. Partition strategy ---
    if partition_columns and set(partition_columns).issubset(colset):
        frames = []

        for d in build_day_list(start_dt, end_dt):
            part_map = {
                "year": f"{d.year:04d}",
                "month": f"{d.month:02d}",
                "day": f"{d.day:02d}",
            }

            parts = [(col, "=", part_map[col]) for col in partition_columns if col in part_map]

            pdf = _safe_partition_read(dt, partitions=parts, columns=cols)
            if pdf is not None and not pdf.empty:
                frames.append(pdf)

        if frames:
            return pd.concat(frames, ignore_index=True)

        return pd.DataFrame(columns=cols)

    # --- 3. Pushdown filter (best case) ---
    if date_column and date_column in colset:
        try:
            tbl = dt.to_pyarrow_table(
                filters=[
                    (date_column, ">=", str(start_dt)),
                    (date_column, "<=", str(end_dt)),
                ]
            )
            return tbl.to_pandas()
        except Exception:
            pass  # fallback below

    # --- 4. Fallback (worst case) ---
    df = dt.to_pandas()

    if date_column and date_column in df.columns:
        date_col = pd.to_datetime(df[date_column], errors="coerce").dt.date
        return df[(date_col >= start_dt) & (date_col <= end_dt)].copy()

    return df


