def _existing_schema(table_path: str, storage_options: Dict[str, str]) -> Optional[pa.Schema]:
    try:
        return DeltaTable(table_path, storage_options=storage_options).schema().to_pyarrow()
    except Exception:
        return None


def _normalize_all_null_cols(df: pd.DataFrame, schema_hint: Optional[pa.Schema]) -> pd.DataFrame:
    out = df.copy()
    hint_map = {f.name: f.type for f in schema_hint} if schema_hint is not None else {}

    for col in out.columns:
        if not out[col].isna().all():
            continue

        field_type = hint_map.get(col)
        if field_type is None:
            out[col] = out[col].astype("string")
        elif pa.types.is_string(field_type) or pa.types.is_large_string(field_type):
            out[col] = out[col].astype("string")
        elif pa.types.is_boolean(field_type):
            out[col] = out[col].astype("boolean")
        elif pa.types.is_integer(field_type):
            out[col] = pd.to_numeric(out[col], errors="coerce").astype("Int64")
        elif pa.types.is_floating(field_type):
            out[col] = pd.to_numeric(out[col], errors="coerce").astype("float64")
        elif pa.types.is_date(field_type):
            out[col] = pd.to_datetime(out[col], errors="coerce").dt.date
        elif pa.types.is_timestamp(field_type):
            out[col] = pd.to_datetime(out[col], errors="coerce", utc=bool(field_type.tz))
        else:
            out[col] = out[col].astype("string")

    return out


def _to_arrow_table(df: pd.DataFrame, schema_hint: Optional[pa.Schema]) -> pa.Table:
    prepped = _normalize_all_null_cols(df, schema_hint)
    tbl = pa.Table.from_pandas(prepped.reset_index(drop=True), preserve_index=False)

    if schema_hint is None:
        return tbl

    schema_cols = [field.name for field in schema_hint]
    current_cols = set(tbl.column_names)

    for field in schema_hint:
        if field.name not in current_cols:
            tbl = tbl.append_column(field.name, pa.nulls(len(tbl), type=field.type))

    ordered = schema_cols + [col for col in tbl.column_names if col not in schema_cols]
    tbl = tbl.select(ordered)

    cast_fields: List[pa.Field] = []
    hint_map = {field.name: field for field in schema_hint}
    for field in tbl.schema:
        if field.name in hint_map:
            hinted = hint_map[field.name]
            cast_fields.append(pa.field(field.name, hinted.type, hinted.nullable))
        else:
            cast_fields.append(field)

    return tbl.cast(pa.schema(cast_fields), safe=False)


def save_df_to_delta(
    df: pd.DataFrame,
    table_path: str,
    *,
    partition_columns: Optional[List[str]] = None,
    truncate_date_columns: Optional[List[str]] = None,
    debug: bool = False,
    dry_run_local: bool = False,
) -> None:
    if df is None or df.empty:
        print(f"No data to write for {table_path}. Skipping write.")
        return

    out = rename_columns_snake_case(df)
    if truncate_date_columns:
        for col in truncate_date_columns:
            if col in out.columns:
                out[col] = pd.to_datetime(out[col], errors="coerce").dt.date

    storage_options = get_storage_options()
    target_schema = _existing_schema(table_path, storage_options)
    table_exists = target_schema is not None

    if target_schema is None:
        target_schema = _to_arrow_table(out, None).schema

    if partition_columns:
        missing = [col for col in partition_columns if col not in out.columns]
        if missing:
            raise ValueError(f"Partition column(s) missing for write: {missing}")

        if not table_exists:
            if debug:
                print(
                    "Creating new partitioned delta table "
                    f"rows={len(out)} partitions={partition_columns}"
                )
            if not dry_run_local:
                write_deltalake(
                    table_path,
                    _to_arrow_table(out, target_schema),
                    mode="overwrite",
                    partition_by=partition_columns,
                    storage_options=storage_options,
                )
            return

        parts = out.dropna(subset=partition_columns)[partition_columns].drop_duplicates()
        if parts.empty:
            print("No non-null partition keys found; writing unpartitioned overwrite.")
            if not dry_run_local:
                write_deltalake(
                    table_path,
                    _to_arrow_table(out, target_schema),
                    mode="overwrite",
                    storage_options=storage_options,
                )
            return

        total = 0
        for _, part in parts.iterrows():
            mask = (out[partition_columns] == part.values).all(axis=1)
            part_df = out.loc[mask].reset_index(drop=True)
            filters = [(col, "=", str(part[col])) for col in partition_columns]

            if debug:
                where_txt = " AND ".join(
                    f"{col}='{part[col]}'" for col in partition_columns
                )
                print(f"Writing partition [{where_txt}] rows={len(part_df)}")

            if not dry_run_local:
                write_deltalake(
                    table_path,
                    _to_arrow_table(part_df, target_schema),
                    mode="overwrite",
                    partition_by=partition_columns,
                    partition_filters=filters,
                    storage_options=storage_options,
                )

            total += len(part_df)

        if debug:
            print(f"Partition write complete. rows={total} partitions={len(parts)}")
        return

    if debug:
        print(f"Writing unpartitioned rows={len(out)} to {table_path}")

    if not dry_run_local:
        write_deltalake(
            table_path,
            _to_arrow_table(out, target_schema),
            mode="overwrite",
            storage_options=storage_options,
        )

