_schema_cache = {}  # simple in-memory cache


def _extract_table_ref(table_path: str) -> str:
    try:
        parts = table_path.split("/Tables/")[1].split("/")
        return f"{parts[0]}.{parts[1]}"
    except Exception:
        raise ValueError(f"Invalid table path: {table_path}")


def _get_table_schema(conn, table_ref: str) -> pd.DataFrame:
    if table_ref in _schema_cache:
        return _schema_cache[table_ref]

    schema, table = table_ref.split(".")

    query = f"""
    SELECT COLUMN_NAME, DATA_TYPE
    FROM INFORMATION_SCHEMA.COLUMNS
    WHERE TABLE_NAME = '{table}'
      AND TABLE_SCHEMA = '{schema}'
    """

    df = conn.query(query)
    _schema_cache[table_ref] = df
    return df


def _build_safe_select(schema_df: pd.DataFrame) -> str:
    return ",\n    ".join([
        f"CONVERT(VARCHAR(64), [{col}], 2) AS [{col}]"
        if dtype.lower() in ("varbinary", "binary", "image")
        else f"[{col}]"
        for col, dtype in zip(schema_df["COLUMN_NAME"], schema_df["DATA_TYPE"])
    ])


def _format_column(col) -> str:
    if isinstance(col, str):
        return f"[{col}]"

    if isinstance(col, tuple):
        name, transform = col

        if transform == "hex":
            return f"CONVERT(VARCHAR(64), [{name}], 2) AS [{name}]"

        raise ValueError(f"Unsupported transform: {transform}")

    raise ValueError(f"Invalid column format: {col}")


def _build_select(columns: list) -> str:
    return ",\n    ".join(_format_column(c) for c in columns)


def read_sql_endpoint(
    table_path: str,
    env: dict,
    columns: list | None = None,
    where: str | None = None,
    top_n: int | None = None,
) -> pd.DataFrame:

    conn = notebookutils.data.connect_to_artifact(
        artifact=env["core_lh_id"],
        workspace=env["workspace_id"],
        artifact_type="Lakehouse"
    )

    table_ref = _extract_table_ref(table_path)

    if columns is None:
        schema_df = _get_table_schema(conn, table_ref)
        select_clause = _build_safe_select(schema_df)
    else:
        select_clause = _build_select(columns)

    top_clause = f"TOP {top_n}" if top_n else ""

    query = f"""
    SELECT {top_clause}
        {select_clause}
    FROM {table_ref}
    """

    if where:
        query += f" WHERE {where}"

    return conn.query(query)

