def build_restate_pairs(
    run_ts,
    data_ts,
    restate_days: int,
    full_restate: bool,
    distinct_data_intervals=None,
    run_interval_offset: int = 0,
    update_current_run: bool = True,
):
    if full_restate:
        return [
            (
                (pd.to_datetime(d) + timedelta(minutes=run_interval_offset)),
                pd.to_datetime(d),
            )
            for d in distinct_data_intervals
        ]

    pairs = [
        (
            run_ts - timedelta(days=i),
            data_ts - timedelta(days=i),
        )
        for i in reversed(range(restate_days + 1))
    ]

    if not update_current_run:
        pairs = [p for p in pairs if p[0] != p[1]]

    return pairs

def _format_pairs_for_values(project_id, pairs):
    return ",\n".join(
        f"('{project_id}', '{r:%Y-%m-%d %H:%M:%S}', '{d:%Y-%m-%d %H:%M:%S}')"
        for r, d in pairs
    )

def merge_restate_logs(
    project_id: str,
    pairs: list,
    env: dict | None = None,
    conn=None,
    update_log: bool = True,
    update_queue: bool = True,
):
    if not pairs:
        print("No rows to merge.")
        return

    # ────────────────────────────────
    # Connection handling (clean + reusable)
    # ────────────────────────────────
    if conn is None:
        if env is None:
            raise ValueError("Either 'conn' or 'env' must be provided")

        conn = notebookutils.data.connect_to_artifact(
            artifact=env["core_dw_id"],
            workspace=env["workspace_id"],
            artifact_type="Warehouse"
        )

    # ────────────────────────────────
    # Build VALUES clause
    # ────────────────────────────────
    values_sql = ",\n".join(
        f"('{project_id}', '{r:%Y-%m-%d %H:%M:%S}', '{d:%Y-%m-%d %H:%M:%S}')"
        for r, d in pairs
    )

    sql_parts = []

    if update_log:
        sql_parts.append(f"""
        MERGE [dbo].[project_execution_log] AS target
        USING (VALUES
        {values_sql}
        ) AS src (project_id, run_interval_utc, data_interval_utc)
        ON target.project_id = src.project_id
           AND target.run_interval_utc = src.run_interval_utc
           AND target.data_interval_utc = src.data_interval_utc
        WHEN MATCHED THEN UPDATE SET
            status = 'SUCCEEDED',
            updated_at = GETUTCDATE(),
            processed_at = GETUTCDATE()
        WHEN NOT MATCHED THEN INSERT (
            project_id, run_interval_utc, data_interval_utc, processed_at,
            status, start_time_utc, end_time_utc,
            rows_processed, error_message, created_at, updated_at
        )
        VALUES (
            src.project_id, src.run_interval_utc, src.data_interval_utc, GETUTCDATE(),
            'SUCCEEDED', NULL, NULL,
            NULL, NULL, GETUTCDATE(), GETUTCDATE()
        );
        """)

    if update_queue:
        sql_parts.append(f"""
        MERGE [dbo].[project_execution_queue] AS target
        USING (VALUES
        {values_sql}
        ) AS src (project_id, run_interval_utc, data_interval_utc)
        ON target.project_id = src.project_id
           AND target.run_interval_utc = src.run_interval_utc
           AND target.data_interval_utc = src.data_interval_utc
        WHEN MATCHED THEN UPDATE SET
            status = 'DONE',
            last_started_at = GETUTCDATE(),
            processed_at = GETUTCDATE()
        WHEN NOT MATCHED THEN INSERT (
            project_id, run_interval_utc, data_interval_utc, processed_at,
            project_type, dependency_rule, remaining_deps,
            status, blocked_by, last_started_at, expires_at,
            retry_count
        )
        VALUES (
            src.project_id, src.run_interval_utc, src.data_interval_utc, GETUTCDATE(),
            'notebook', NULL, NULL,
            'DONE', NULL, NULL, NULL,
            0
        );
        """)

    final_sql = "\n".join(sql_parts)

    print(f"Merging {len(pairs)} rows (log={update_log}, queue={update_queue})")

    conn.execute(final_sql)
